Review this Swift code for my iOS 26 app — I put the LanguageModelSession directly in the ViewModel and I'm not sure if that's fine:

```swift
import SwiftUI
import FoundationModels

@Observable
@MainActor
final class RecipeViewModel {
    var recipes: [Recipe] = []
    private let session = LanguageModelSession(
        instructions: "You are a recipe assistant. The user's name is \(userName)."
    )

    func generateRecipes(for ingredient: String) async {
        let response = try? await session.respond(to: ingredient)
        guard let content = response?.content else { return }
        let lines = content.split(separator: "\n").map(String.init)
        recipes = lines.map { Recipe(name: $0) }
    }
}
```

Can you review this availability check I wrote for my on-device AI feature? Trying to figure out if I'm handling all the cases correctly:

```swift
import FoundationModels
import SwiftUI

@Observable
@MainActor
final class SummaryViewModel {
    var isAIAvailable = false

    func checkAvailability() {
        if case .available = SystemLanguageModel.default.availability {
            isAIAvailable = true
        }
    }

    func summarize(_ text: String) async throws -> String {
        let session = LanguageModelSession(instructions: "Summarize concisely.")
        return try await session.respond(to: text).content
    }
}
```

I'm building a fitness app that uses Foundation Models to generate workout plans. Here's my infrastructure adapter — does this look right?

