import FoundationModels
import Foundation

final class WorkoutPlanService {
    private var session = LanguageModelSession(
        instructions: "You are a fitness coach. Generate structured workout plans."
    )

    func generatePlan(for goal: String) async throws -> WorkoutPlan {
        let response = try await session.respond(
            to: goal,
            generating: WorkoutPlan.self
        )
        return response.content
    }
}

